create or replace view public.courier_receivable_summary with(security_invoker=true)as
select s.organization_id,s.courier_id,sum(s.expected_cod_minor)::bigint as contractual_cod_minor,coalesce(sum(s.reported_collected_cod_minor),0)::bigint as courier_reported_cod_minor,(sum(s.courier_delivery_fee_minor)+coalesce(sum(rf.return_fees_minor),0))::bigint as accrued_courier_fees_minor,count(*)filter(where s.settlement_status<>'settled')::bigint as unsettled_shipments
from public.shipments s left join lateral(select sum(r.courier_return_fee_minor)::bigint as return_fees_minor from public.returns r where r.organization_id=s.organization_id and r.shipment_id=s.id and r.status='resolved')rf on true
where s.status in('partially_delivered','delivered','returned')group by s.organization_id,s.courier_id;

do $repair$
declare d text;f text;
begin
select pg_get_functiondef('private.command_record_order_return(uuid,uuid,text,jsonb,text,uuid,integer,text,text,uuid)'::regprocedure)into d;
f:=replace(d,'update public.shipments set status=case when not exists','update public.shipments set settlement_status=''unsettled'',status=case when not exists');
if f=d then raise exception 'RETURN_SETTLEMENT_STATUS_REPAIR_NOT_APPLIED';end if;execute f;
end;$repair$;
revoke all on function private.command_record_order_return(uuid,uuid,text,jsonb,text,uuid,integer,text,text,uuid)from public,anon,authenticated;
grant execute on function private.command_record_order_return(uuid,uuid,text,jsonb,text,uuid,integer,text,text,uuid)to authenticated;
